import { db } from "@db/app/client";
import { orgWorkflowRuns } from "@db/app/schema";
import type { TRPCRouterRecord } from "@trpc/server";
import { and, desc, eq, sql } from "drizzle-orm";
import { z } from "zod";
import { orgScopedProcedure } from "../../trpc";

/**
 * Jobs router - procedures for querying and managing workflow jobs
 */
export const jobsRouter = {
  /**
   * List jobs with filters and pagination
   * Returns jobs for the current org with optional filters
   */
  list: orgScopedProcedure
    .input(
      z.object({
        status: z
          .enum(["queued", "running", "completed", "failed", "cancelled"])
          .optional(),
        repositoryId: z.string().optional(),
        limit: z.number().min(1).max(100).default(20),
        cursor: z.string().optional(), // createdAt timestamp for cursor pagination
      })
    )
    .query(async ({ ctx, input }) => {
      const clerkOrgId = ctx.auth.orgId;
      const { status, repositoryId, limit, cursor } = input;

      // Build where conditions
      const conditions = [eq(orgWorkflowRuns.clerkOrgId, clerkOrgId)];

      if (status) {
        conditions.push(eq(orgWorkflowRuns.status, status));
      }

      if (repositoryId) {
        conditions.push(eq(orgWorkflowRuns.repositoryId, repositoryId));
      }

      if (cursor) {
        conditions.push(sql`${orgWorkflowRuns.createdAt} < ${cursor}`);
      }

      // Query jobs with limit + 1 to determine if there are more
      const jobsList = await db
        .select()
        .from(orgWorkflowRuns)
        .where(and(...conditions))
        .orderBy(desc(orgWorkflowRuns.createdAt))
        .limit(limit + 1);

      const hasMore = jobsList.length > limit;
      const items = hasMore ? jobsList.slice(0, limit) : jobsList;
      const nextCursor = hasMore ? items.at(-1)?.createdAt : null;

      return { items, nextCursor, hasMore };
    }),
} satisfies TRPCRouterRecord;

"use client";

import { useTRPC } from "@repo/app-trpc/react";
import { TeamSwitcher } from "@repo/ui/components/app-header/team-switcher";
import { Button } from "@repo/ui/components/ui/button";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@repo/ui/components/ui/popover";
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@repo/ui/components/ui/sidebar";
import { useSuspenseQuery } from "@tanstack/react-query";
import { useOrganizationList } from "@vendor/clerk/client";
import { BookOpen, HelpCircle, Mail } from "lucide-react";
import Link from "next/link";
import { usePathname } from "next/navigation";

/**
 * Navigation item types
 */
interface NavItem {
  href: string;
  title: string;
}

/**
 * Build primary navigation items for org-level pages
 */
function getOrgPrimaryItems(orgSlug: string): NavItem[] {
  return [
    {
      title: "Ask",
      href: `/${orgSlug}`,
    },
    {
      title: "Search",
      href: `/${orgSlug}/search`,
    },
  ];
}

/**
 * Build management navigation items for org-level pages
 */
function getOrgManageItems(orgSlug: string): NavItem[] {
  return [
    {
      title: "Events",
      href: `/${orgSlug}/events`,
    },
    {
      title: "Sources",
      href: `/${orgSlug}/sources`,
    },
    {
      title: "Jobs",
      href: `/${orgSlug}/jobs`,
    },
    {
      title: "Settings",
      href: `/${orgSlug}/settings`,
    },
  ];
}

/**
 * Render a set of navigation items as a proper component for correct reconciliation
 */
function NavItems({ items, pathname }: { items: NavItem[]; pathname: string }) {
  return items.map((item) => {
    // For Settings, match any settings subpage (org or workspace level)
    const isActive =
      item.title === "Settings"
        ? pathname.startsWith(item.href)
        : pathname === item.href;

    return (
      <SidebarMenuItem key={item.title}>
        <SidebarMenuButton asChild isActive={isActive} size="sm">
          <Link href={{ pathname: item.href }} prefetch={true}>
            <span>{item.title}</span>
          </Link>
        </SidebarMenuButton>
      </SidebarMenuItem>
    );
  });
}

/**
 * PlanetScale-style sidebar component for the Console app
 */
export function AppSidebar() {
  const pathname = usePathname();
  const trpc = useTRPC();
  const { setActive } = useOrganizationList();

  const { data: organizations = [] } = useSuspenseQuery({
    ...trpc.organization.listUserOrganizations.queryOptions(),
    refetchOnMount: false,
    refetchOnWindowFocus: false,
    staleTime: 5 * 60 * 1000,
  });

  const handleOrgSelect = async (orgId: string) => {
    if (setActive) {
      await setActive({ organization: orgId });
    }
  };

  // Extract orgSlug from pathname
  // Pathname format: /[slug]/...
  const pathParts = pathname.split("/").filter(Boolean);
  const orgSlug = pathParts[0] ?? ""; // [slug]

  // Determine mode based on pathname
  const mode =
    pathname.startsWith("/account") || pathname.startsWith("/new")
      ? "account"
      : "organization";

  return (
    <Sidebar
      className="group/sidebar border-border/50 border-r"
      collapsible="none"
      variant="inset"
    >
      {/* Org component header - only show if in org context */}
      {orgSlug && (
        <div className="flex h-14 items-center px-4">
          <TeamSwitcher
            createTeamHref="/account/teams/new"
            mode={mode}
            onOrgSelect={handleOrgSelect}
            organizations={organizations}
          />
        </div>
      )}
      <SidebarContent>
        {orgSlug && (
          <>
            {/* Primary Navigation - no label */}
            <SidebarGroup>
              <SidebarGroupContent>
                <SidebarMenu>
                  <NavItems
                    items={getOrgPrimaryItems(orgSlug)}
                    pathname={pathname}
                  />
                </SidebarMenu>
              </SidebarGroupContent>
            </SidebarGroup>

            {/* Manage Section - with label */}
            <SidebarGroup>
              <SidebarGroupLabel>Manage</SidebarGroupLabel>
              <SidebarGroupContent>
                <SidebarMenu>
                  <NavItems
                    items={getOrgManageItems(orgSlug)}
                    pathname={pathname}
                  />
                </SidebarMenu>
              </SidebarGroupContent>
            </SidebarGroup>
          </>
        )}
      </SidebarContent>
      <SidebarFooter>
        <Popover>
          <PopoverTrigger asChild>
            <Button
              className="rounded-full bg-muted p-1"
              size="icon"
              title="Help"
              variant="outline"
            >
              <HelpCircle className="h-3 w-3" />
            </Button>
          </PopoverTrigger>
          <PopoverContent align="center" className="w-48 p-1">
            <div className="flex flex-col gap-1">
              <Button
                asChild
                className="justify-start gap-2 text-sm"
                size="sm"
                variant="ghost"
              >
                <a href="mailto:support@lightfast.ai">
                  <Mail className="size-3" />
                  Contact Support
                </a>
              </Button>
              <Button
                asChild
                className="justify-start gap-2 text-sm"
                size="sm"
                variant="ghost"
              >
                <Link
                  href="https://lightfast.ai/docs/get-started/overview"
                  rel="noopener noreferrer"
                  target="_blank"
                >
                  <BookOpen className="size-3" />
                  Help Docs
                </Link>
              </Button>
            </div>
          </PopoverContent>
        </Popover>
      </SidebarFooter>
    </Sidebar>
  );
}

import type { EntityCategory } from "@repo/app-validation";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  integer,
  jsonb,
  pgTable,
  real,
  text,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";

/**
 * Org entities extracted from events
 *
 * Stores structured entities discovered in event content.
 * Entities are deduplicated by (clerkOrgId, category, key) and
 * occurrence counts track how many times each entity is seen.
 */
export const orgEntities = pgTable(
  "lightfast_org_entities",
  {
    /**
     * Internal BIGINT primary key - maximum join/query performance
     */
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    /**
     * External identifier for API responses
     */
    externalId: varchar("external_id", { length: 21 })
      .notNull()
      .$defaultFn(() => nanoid()),

    /**
     * Clerk org ID (no FK — Clerk is source of truth).
     */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    // ========== ENTITY IDENTITY ==========

    /**
     * Entity category (engineer, project, endpoint, etc.)
     */
    category: varchar("category", { length: 50 })
      .notNull()
      .$type<EntityCategory>(),

    /**
     * Canonical entity key (e.g., "@sarah", "POST /api/users", "#123")
     */
    key: varchar("key", { length: 500 }).notNull(),

    /**
     * Human-readable value/description
     */
    value: text("value"),

    /**
     * Alternative names for this entity (e.g., ["sarah@acme.com", "Sarah J"])
     */
    aliases: jsonb("aliases").$type<string[]>(),

    // ========== PROVENANCE ==========

    /**
     * Text snippet providing evidence for extraction
     */
    evidenceSnippet: text("evidence_snippet"),

    /**
     * Extraction confidence score (0.0 - 1.0)
     */
    confidence: real("confidence").default(0.8),

    /**
     * Entity lifecycle state (e.g., "open", "merged", "resolved", "closed")
     */
    state: varchar("state", { length: 100 }),

    /**
     * Canonical source URL for this entity
     */
    url: varchar("url", { length: 2048 }),

    // ========== METRICS ==========

    /**
     * When this entity was first extracted
     */
    extractedAt: timestamp("extracted_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    /**
     * When this entity was last seen in an event
     */
    lastSeenAt: timestamp("last_seen_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    /**
     * Number of times this entity has been extracted
     */
    occurrenceCount: integer("occurrence_count").default(1).notNull(),

    // ========== TIMESTAMPS ==========

    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    updatedAt: timestamp("updated_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    // External ID lookup (API requests)
    externalIdIdx: uniqueIndex("org_entity_external_id_idx").on(
      table.externalId
    ),

    // Unique constraint for deduplication — (clerkOrgId, category, key)
    uniqueEntityKey: uniqueIndex("org_entity_clerk_org_category_key_idx").on(
      table.clerkOrgId,
      table.category,
      table.key
    ),

    // Lookup by org and category
    orgCategoryIdx: index("org_entity_org_category_idx").on(
      table.clerkOrgId,
      table.category
    ),

    // Key search
    orgKeyIdx: index("org_entity_org_key_idx").on(table.clerkOrgId, table.key),

    // Last seen for cleanup/ranking
    orgLastSeenIdx: index("org_entity_org_last_seen_idx").on(
      table.clerkOrgId,
      table.lastSeenAt
    ),
  })
);

// Type exports
export type OrgEntity = typeof orgEntities.$inferSelect;
export type InsertOrgEntity = typeof orgEntities.$inferInsert;

import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  jsonb,
  pgTable,
  real,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";
import { orgEntities } from "./org-entities";
import { orgEvents } from "./org-events";

/**
 * Entity↔entity directed edges.
 *
 * Replaces observation↔observation edges. Relationships exist between
 * entities (e.g., commit deploys deployment), not between events.
 * The sourceEventId provides provenance — which event caused this edge.
 */
export const orgEntityEdges = pgTable(
  "lightfast_org_entity_edges",
  {
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    externalId: varchar("external_id", { length: 21 })
      .notNull()
      .$defaultFn(() => nanoid()),

    // Clerk org ID (no FK — Clerk is source of truth)
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    sourceEntityId: bigint("source_entity_id", { mode: "number" })
      .notNull()
      .references(() => orgEntities.id, { onDelete: "cascade" }),

    targetEntityId: bigint("target_entity_id", { mode: "number" })
      .notNull()
      .references(() => orgEntities.id, { onDelete: "cascade" }),

    relationshipType: varchar("relationship_type", { length: 50 }).notNull(),

    sourceEventId: bigint("source_event_id", { mode: "number" }).references(
      () => orgEvents.id,
      { onDelete: "set null" }
    ),

    confidence: real().default(1.0).notNull(),

    lastSeenAt: timestamp("last_seen_at", { withTimezone: true })
      .notNull()
      .default(sql`CURRENT_TIMESTAMP`),

    metadata: jsonb().$type<Record<string, unknown>>(),

    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    externalIdIdx: uniqueIndex("org_edge_external_id_idx").on(table.externalId),
    sourceIdx: index("org_edge_source_idx").on(
      table.clerkOrgId,
      table.sourceEntityId
    ),
    targetIdx: index("org_edge_target_idx").on(
      table.clerkOrgId,
      table.targetEntityId
    ),
    uniqueEdgeIdx: uniqueIndex("org_edge_unique_idx").on(
      table.clerkOrgId,
      table.sourceEntityId,
      table.targetEntityId,
      table.relationshipType
    ),
    sourceEventIdx: index("org_edge_source_event_idx").on(table.sourceEventId),
  })
);

export type OrgEntityEdge = typeof orgEntityEdges.$inferSelect;
export type InsertOrgEntityEdge = typeof orgEntityEdges.$inferInsert;

import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  pgTable,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";
import { orgEntities } from "./org-entities";
import { orgEvents } from "./org-events";

/**
 * Entity↔Event junction table.
 *
 * Records every occurrence of an entity in an event,
 * replacing the single source_event_id FK on the entity table.
 * Enables "all events for entity X" and "all entities for event Y".
 */
export const orgEventEntities = pgTable(
  "lightfast_org_event_entities",
  {
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    entityId: bigint("entity_id", { mode: "number" })
      .notNull()
      .references(() => orgEntities.id, { onDelete: "cascade" }),

    eventId: bigint("event_id", { mode: "number" })
      .notNull()
      .references(() => orgEvents.id, {
        onDelete: "cascade",
      }),

    // Clerk org ID (no FK — Clerk is source of truth)
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    /** Contextual label from reference (e.g., "resolved_by", "fixes", null) */
    refLabel: varchar("ref_label", { length: 50 }),

    /** Entity category denormalized from orgEntities for join-free edge resolution */
    category: varchar("category", { length: 50 }),

    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    // Unique constraint: one junction row per entity+event pair
    uniqueEntityEvent: uniqueIndex("org_event_entity_idx").on(
      table.entityId,
      table.eventId
    ),

    // "All events for entity X"
    entityIdx: index("org_event_entity_entity_idx").on(table.entityId),

    // "All entities for event Y"
    eventIdx: index("org_event_entity_event_idx").on(table.eventId),
  })
);

export type OrgEventEntity = typeof orgEventEntities.$inferSelect;
export type InsertOrgEventEntity = typeof orgEventEntities.$inferInsert;

import type { EntityRelation } from "@repo/app-providers/contracts";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";
import { orgIngestLogs } from "./org-ingest-logs";

/**
 * Org events - atomic engineering events from GitHub, Vercel, etc.
 */
export const orgEvents = pgTable(
  "lightfast_org_events",
  {
    /**
     * Internal BIGINT primary key - maximum join/query performance
     */
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    /**
     * External identifier for API responses and Pinecone metadata
     */
    externalId: varchar("external_id", { length: 21 })
      .notNull()
      .$defaultFn(() => nanoid()),

    /**
     * Clerk org ID (no FK — Clerk is source of truth).
     */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    // ========== TEMPORAL ==========

    /**
     * When the event occurred in the source system
     */
    occurredAt: timestamp("occurred_at", {
      mode: "string",
      withTimezone: true,
    }).notNull(),

    /**
     * When the event was captured
     */
    capturedAt: timestamp("captured_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    // ========== CONTENT ==========

    /**
     * Observation type (e.g., "pr_merged", "deployment_succeeded")
     */
    observationType: varchar("observation_type", { length: 100 }).notNull(),

    /**
     * Short title (<=120 chars, embeddable headline)
     */
    title: text("title").notNull(),

    /**
     * Full content for detailed embedding
     */
    content: text("content").notNull(),

    // ========== SOURCE ==========

    /**
     * Source system (github, vercel, linear, sentry)
     */
    source: varchar("source", { length: 50 }).notNull(),

    /**
     * Source-specific event type (e.g., "pull_request_merged")
     */
    sourceType: varchar("source_type", { length: 100 }).notNull(),

    /**
     * Unique source identifier (e.g., "pr:lightfastai/lightfast#123")
     */
    sourceId: varchar("source_id", { length: 255 }).notNull(),

    /**
     * References to related entities
     */
    sourceReferences: jsonb("source_references").$type<EntityRelation[]>(),

    /**
     * Source-specific attributes
     */
    metadata:
      jsonb("metadata").$type<
        Record<string, string | number | boolean | null>
      >(),

    // ========== INGESTION ==========

    /**
     * How this event was ingested: webhook, backfill, manual, or api
     */
    ingestionSource: varchar("ingestion_source", { length: 20 })
      .default("webhook")
      .notNull(),

    /**
     * FK back to the ingest log that produced this event.
     * Null for backfill-ingested events and test-data paths.
     */
    ingestLogId: bigint("ingest_log_id", { mode: "number" }).references(
      () => orgIngestLogs.id,
      { onDelete: "set null" }
    ),

    /**
     * Significance score (0-100) computed at ingestion time.
     * Used for search ranking and notification thresholds.
     * Null for events ingested before this column was added.
     */
    significanceScore: integer("significance_score"),

    // ========== TIMESTAMPS ==========

    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    // External ID lookup (API requests)
    externalIdIdx: uniqueIndex("org_event_external_id_idx").on(
      table.externalId
    ),

    // Org + time range queries
    orgOccurredIdx: index("org_event_org_occurred_idx").on(
      table.clerkOrgId,
      table.occurredAt
    ),

    // Source filtering
    sourceIdx: index("org_event_source_idx").on(
      table.clerkOrgId,
      table.source,
      table.sourceType
    ),

    // Deduplication by source ID
    sourceIdIdx: index("org_event_source_id_idx").on(
      table.clerkOrgId,
      table.sourceId
    ),

    // Type filtering
    typeIdx: index("org_event_type_idx").on(
      table.clerkOrgId,
      table.observationType
    ),
  })
);

// Type exports
export type OrgEvent = typeof orgEvents.$inferSelect;
export type InsertOrgEvent = typeof orgEvents.$inferInsert;

