458	
459	        // Primary entity is always at index 0 (inserted first in extractedEntities,
460	        // Map insertion order preserved, and confidence 1.0 ensures it wins dedup).
461	        const primaryEntityExternalId =
462	          entityResults[0]?.[0]?.externalId ?? null;
463	
