"use client";

import { providerSlugSchema } from "@repo/app-providers/client";
import { parseAsString, parseAsStringEnum, useQueryStates } from "nuqs";
import { AGE_PRESET_OPTIONS } from "~/components/search-constants";

const SOURCE_OPTIONS = ["all", ...providerSlugSchema.options] as const;
const AGE_OPTIONS = AGE_PRESET_OPTIONS.map((o) => o.value);

export type EventSource = (typeof SOURCE_OPTIONS)[number];
export type EventAge = (typeof AGE_PRESET_OPTIONS)[number]["value"];

export function useEventFilters(initialSource?: string) {
  const [filters, setFilters] = useQueryStates(
    {
      source: parseAsStringEnum<EventSource>([...SOURCE_OPTIONS]).withDefault(
        (initialSource ?? "all") as EventSource
      ),
      search: parseAsString.withDefault(""),
      age: parseAsStringEnum<EventAge>([...AGE_OPTIONS]).withDefault("none"),
    },
    { history: "replace", shallow: true }
  );

  return { filters, setFilters };
}

import {
  PROVIDER_DISPLAY,
  type ProviderSlug,
} from "@repo/app-providers/client";
import { Skeleton } from "@repo/ui/components/ui/skeleton";
import { Suspense } from "react";
import { EventsTable } from "./_components/events-table";

export default async function EventsPage({
  searchParams,
}: {
  searchParams: Promise<Record<string, string | string[] | undefined>>;
}) {
  const search = await searchParams;

  const initialSource =
    typeof search.source === "string" &&
    Object.keys(PROVIDER_DISPLAY).includes(search.source)
      ? (search.source as ProviderSlug)
      : undefined;

  return (
    <div className="pb-6">
      <div className="mb-6">
        <h1 className="font-semibold text-2xl tracking-tight">Events</h1>
        <p className="mt-1 text-muted-foreground text-sm">
          Real-time activity from your connected sources.
        </p>
      </div>

      <Suspense fallback={<EventsFeedSkeleton />}>
        <EventsTable initialSource={initialSource} />
      </Suspense>
    </div>
  );
}

function EventsFeedSkeleton() {
  return (
    <div className="space-y-4">
      <Skeleton className="h-10 w-80" />
      <div className="overflow-hidden rounded-lg border border-border/60">
        {Array.from({ length: 8 }, (_, i) => (
          <div className="border-border/60 border-b px-4 py-3" key={i}>
            <div className="flex items-start gap-3">
              <Skeleton className="mt-0.5 h-5 w-5 rounded" />
              <div className="flex-1 space-y-2">
                <Skeleton className="h-4 w-3/4" />
                <Skeleton className="h-3 w-1/3" />
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

