import { PROVIDER_DISPLAY } from "@repo/app-providers/client";
import type { LucideIcon } from "lucide-react";
import { Scale, Zap } from "lucide-react";

export const SOURCE_TYPE_OPTIONS = Object.entries(PROVIDER_DISPLAY).map(
  ([value, entry]) => ({ value, label: entry.displayName })
);

export const OBSERVATION_TYPE_OPTIONS = [
  // GitHub
  { value: "push", label: "Push" },
  { value: "pull_request_opened", label: "PR Opened" },
  { value: "pull_request_merged", label: "PR Merged" },
  { value: "pull_request_closed", label: "PR Closed" },
  { value: "issue_opened", label: "Issue Opened" },
  { value: "issue_closed", label: "Issue Closed" },
  // Vercel
  { value: "deployment_succeeded", label: "Deploy Success" },
  { value: "deployment_error", label: "Deploy Error" },
  // Sentry
  { value: "issue.created", label: "Issue Created" },
  { value: "issue.resolved", label: "Issue Resolved" },
  { value: "error.created", label: "Error Created" },
  { value: "alert.triggered", label: "Alert Triggered" },
  // Linear
  { value: "issue.updated", label: "Issue Updated" },
  { value: "issue.completed", label: "Issue Completed" },
  { value: "comment.created", label: "Comment Created" },
] as const;

export const MODE_OPTIONS: {
  value: string;
  label: string;
  icon: LucideIcon;
  description: string;
}[] = [
  {
    value: "fast",
    label: "Fast",
    icon: Zap,
    description: "Vector scores only (~50ms)",
  },
  {
    value: "balanced",
    label: "Auto",
    icon: Scale,
    description: "Cohere rerank (~130ms)",
  },
];

export const AGE_PRESET_OPTIONS = [
  { value: "1h", label: "1 hour" },
  { value: "6h", label: "6 hours" },
  { value: "24h", label: "24 hours" },
  { value: "72h", label: "3 days" },
  { value: "7d", label: "7 days" },
  { value: "30d", label: "30 days" },
  { value: "none", label: "No limit" },
] as const;

export function dateRangeFromPreset(preset: string): {
  after?: string;
} {
  if (preset === "none") {
    return {};
  }
  const hoursMap: Record<string, number> = {
    "1h": 1,
    "6h": 6,
    "24h": 24,
    "72h": 72,
    "7d": 168,
    "30d": 720,
  };
  const hours = hoursMap[preset];
  if (!hours) {
    return {};
  }
  const after = new Date(Date.now() - hours * 60 * 60 * 1000).toISOString();
  return { after };
}

